def pagerank_cycle(ranks, links, d=0.85):
    new_ranks = {}
    # Teleportation
    for node in ranks: new_ranks[node] = (1 - d)

    # Power Flow
    for source, targets in links.items():
        share = d * ranks[source] / len(targets)
        for t in targets:
            new_ranks[t] += share
    return new_ranks

# B links to A and C
links = {'B': ['A', 'C'], 'A': ['C'], 'C': ['A']}
r = {'A': 1, 'B': 1, 'C': 1}
print(f"Iteration 1: {pagerank_cycle(r, links)}")
